     1→/**
     2→ * PM Slice
     3→ *
     4→ * State management for PM schedules, drag-drop interactions, and constraints.
     5→ * Handles real-time validation during drag operations.
     6→ *
     7→ * @see specs/006-user-interface.md Section 6.4
     8→ */
     9→
    10→import { createSlice, createAsyncSlice } from '@belt/tools';
    11→import type {
    12→  PmScheduleEntry,
    13→  PmType,
    14→  DragState,
    15→  ConstraintViolation,
    16→  PmStatus,
    17→} from '../types';
    18→
    19→// =============================================================================
    20→// PM Slice State
    21→// =============================================================================
    22→
    23→interface UndoEntry {
    24→  pmId: string;
    25→  previousDate: string;
    26→  newDate: string;
    27→  timestamp: number;
    28→}
    29→
    30→interface PendingMove {
    31→  targetDate: string;
    32→  originalDate: string;
    33→}
    34→
    35→export interface PmSliceState {
    36→  pmSchedule: PmScheduleEntry[];
    37→  pmTypes: PmType[];
    38→  drag: DragState;
    39→  lockedPmIds: Record<string, boolean>;
    40→  editingPmId: string | null;
    41→  pendingMoves: Record<string, PendingMove>;
    42→  constraintCache: Record<string, ConstraintViolation[]>;
    43→  lastValidation: number | null;
    44→  undoStack: UndoEntry[];
    45→  maxUndoDepth: number;
    46→  [key: string]: unknown;
    47→}
    48→
    49→const initialPmState: PmSliceState = {
    50→  pmSchedule: [],
    51→  pmTypes: [],
    52→  drag: {
    53→    isDragging: false,
    54→    pmId: null,
    55→    sourceDate: null,
    56→    targetDate: null,
    57→    isValid: true,
    58→    validationMessage: null,
    59→    constraintViolations: [],
    60→  },
    61→  lockedPmIds: {},
    62→  editingPmId: null,
    63→  pendingMoves: {},
    64→  constraintCache: {},
    65→  lastValidation: null,
    66→  undoStack: [],
    67→  maxUndoDepth: 50,
    68→};
    69→
    70→export const pmSlice = createSlice({
    71→  id: 'pm',
    72→  initial: initialPmState,
    73→  cache: { policy: 'session' },
    74→  reducers: {
    75→    // PM Schedule Operations
    76→    setPmSchedule: (s, schedule: PmScheduleEntry[]) => {
    77→      const state = s as PmSliceState;
    78→      state.pmSchedule = schedule;
    79→    },
    80→
    81→    setPmTypes: (s, types: PmType[]) => {
    82→      const state = s as PmSliceState;
    83→      state.pmTypes = types;
    84→    },
    85→
    86→    updatePm: (s, pm: Partial<PmScheduleEntry> & { id: string }) => {
    87→      const state = s as PmSliceState;
    88→      const index = state.pmSchedule.findIndex((p) => p.id === pm.id);
    89→      if (index !== -1) {
    90→        state.pmSchedule[index] = { ...state.pmSchedule[index], ...pm };
    91→      }
    92→    },
    93→
    94→    addPm: (s, pm: PmScheduleEntry) => {
    95→      const state = s as PmSliceState;
    96→      state.pmSchedule.push(pm);
    97→    },
    98→
    99→    removePm: (s, pmId: string) => {
   100→      const state = s as PmSliceState;
   101→      state.pmSchedule = state.pmSchedule.filter((p) => p.id !== pmId);
   102→    },
   103→
   104→    updatePmStatus: (s, payload: { pmId: string; status: PmStatus }) => {
   105→      const state = s as PmSliceState;
   106→      const pm = state.pmSchedule.find((p) => p.id === payload.pmId);
   107→      if (pm) {
   108→        pm.status = payload.status;
   109→      }
   110→    },
   111→
   112→    // Drag and Drop
   113→    startDrag: (s, payload: { pmId: string; sourceDate: string }) => {
   114→      const state = s as PmSliceState;
   115→      if (state.lockedPmIds[payload.pmId]) {
   116→        return;
   117→      }
   118→
   119→      state.drag = {
   120→        isDragging: true,
   121→        pmId: payload.pmId,
   122→        sourceDate: payload.sourceDate,
   123→        targetDate: payload.sourceDate,
   124→        isValid: true,
   125→        validationMessage: null,
   126→        constraintViolations: [],
   127→      };
   128→    },
   129→
   130→    updateDragTarget: (s, targetDate: string) => {
   131→      const state = s as PmSliceState;
   132→      if (!state.drag.isDragging) return;
   133→
   134→      state.drag.targetDate = targetDate;
   135→
   136→      const cacheKey = `${state.drag.pmId}:${targetDate}`;
   137→      const cachedViolations = state.constraintCache[cacheKey];
   138→
   139→      if (cachedViolations) {
   140→        state.drag.constraintViolations = cachedViolations;
   141→        state.drag.isValid = cachedViolations.every((v) => v.severity !== 'ERROR');
   142→        state.drag.validationMessage =
   143→          cachedViolations.length > 0
   144→            ? cachedViolations.map((v) => v.message).join('; ')
   145→            : null;
   146→      }
   147→    },
   148→
   149→    setDragValidation: (
   150→      s,
   151→      payload: {
   152→        isValid: boolean;
   153→        message: string | null;
   154→        violations: ConstraintViolation[];
   155→      }
   156→    ) => {
   157→      const state = s as PmSliceState;
   158→      state.drag.isValid = payload.isValid;
   159→      state.drag.validationMessage = payload.message;
   160→      state.drag.constraintViolations = payload.violations;
   161→
   162→      if (state.drag.pmId && state.drag.targetDate) {
   163→        const cacheKey = `${state.drag.pmId}:${state.drag.targetDate}`;
   164→        state.constraintCache[cacheKey] = payload.violations;
   165→      }
   166→      state.lastValidation = Date.now();
   167→    },
   168→
   169→    endDrag: (s, commit: boolean) => {
   170→      const state = s as PmSliceState;
   171→      if (!state.drag.isDragging || !state.drag.pmId) {
   172→        state.drag = {
   173→          isDragging: false,
   174→          pmId: null,
   175→          sourceDate: null,
   176→          targetDate: null,
   177→          isValid: true,
   178→          validationMessage: null,
   179→          constraintViolations: [],
   180→        };
   181→        return;
   182→      }
   183→
   184→      if (commit && state.drag.isValid && state.drag.targetDate !== state.drag.sourceDate) {
   185→        const pm = state.pmSchedule.find((p) => p.id === state.drag.pmId);
   186→        if (pm) {
   187→          state.undoStack.push({
   188→            pmId: state.drag.pmId,
   189→            previousDate: state.drag.sourceDate!,
   190→            newDate: state.drag.targetDate!,
   191→            timestamp: Date.now(),
   192→          });
   193→
   194→          if (state.undoStack.length > state.maxUndoDepth) {
   195→            state.undoStack.shift();
   196→          }
   197→
   198→          pm.targetDate = state.drag.targetDate!;
   199→
   200→          state.pendingMoves[state.drag.pmId] = {
   201→            targetDate: state.drag.targetDate!,
   202→            originalDate: state.drag.sourceDate!,
   203→          };
   204→        }
   205→      }
   206→
   207→      state.drag = {
   208→        isDragging: false,
   209→        pmId: null,
   210→        sourceDate: null,
   211→        targetDate: null,
   212→        isValid: true,
   213→        validationMessage: null,
   214→        constraintViolations: [],
   215→      };
   216→    },
   217→
   218→    cancelDrag: (s) => {
   219→      const state = s as PmSliceState;
   220→      state.drag = {
   221→        isDragging: false,
   222→        pmId: null,
   223→        sourceDate: null,
   224→        targetDate: null,
   225→        isValid: true,
   226→        validationMessage: null,
   227→        constraintViolations: [],
   228→      };
   229→    },
   230→
   231→    // Undo/Redo
   232→    undoLastMove: (s) => {
   233→      const state = s as PmSliceState;
   234→      const lastMove = state.undoStack.pop();
   235→      if (lastMove) {
   236→        const pm = state.pmSchedule.find((p) => p.id === lastMove.pmId);
   237→        if (pm) {
   238→          pm.targetDate = lastMove.previousDate;
   239→          delete state.pendingMoves[lastMove.pmId];
   240→        }
   241→      }
   242→    },
   243→
   244→    clearUndoStack: (s) => {
   245→      const state = s as PmSliceState;
   246→      state.undoStack = [];
   247→    },
   248→
   249→    // Locking
   250→    lockPm: (s, pmId: string) => {
   251→      const state = s as PmSliceState;
   252→      state.lockedPmIds[pmId] = true;
   253→      const pm = state.pmSchedule.find((p) => p.id === pmId);
   254→      if (pm) {
   255→        pm.isLocked = true;
   256→      }
   257→    },
   258→
   259→    unlockPm: (s, pmId: string) => {
   260→      const state = s as PmSliceState;
   261→      delete state.lockedPmIds[pmId];
   262→      const pm = state.pmSchedule.find((p) => p.id === pmId);
   263→      if (pm) {
   264→        pm.isLocked = false;
   265→        pm.lockedBy = null;
   266→        pm.lockedAt = null;
   267→      }
   268→    },
   269→
   270→    setLockedPms: (s, pmIds: string[]) => {
   271→      const state = s as PmSliceState;
   272→      state.lockedPmIds = {};
   273→      pmIds.forEach((id) => {
   274→        state.lockedPmIds[id] = true;
   275→      });
   276→    },
   277→
   278→    // Editing
   279→    startEditing: (s, pmId: string) => {
   280→      const state = s as PmSliceState;
   281→      if (!state.lockedPmIds[pmId]) {
   282→        state.editingPmId = pmId;
   283→      }
   284→    },
   285→
   286→    stopEditing: (s) => {
   287→      const state = s as PmSliceState;
   288→      state.editingPmId = null;
   289→    },
   290→
   291→    // Pending Moves
   292→    confirmMove: (s, pmId: string) => {
   293→      const state = s as PmSliceState;
   294→      delete state.pendingMoves[pmId];
   295→    },
   296→
   297→    rejectMove: (s, pmId: string) => {
   298→      const state = s as PmSliceState;
   299→      const pending = state.pendingMoves[pmId];
   300→      if (pending) {
   301→        const pm = state.pmSchedule.find((p) => p.id === pmId);
   302→        if (pm) {
   303→          pm.targetDate = pending.originalDate;
   304→        }
   305→        delete state.pendingMoves[pmId];
   306→      }
   307→    },
   308→
   309→    clearPendingMoves: (s) => {
   310→      const state = s as PmSliceState;
   311→      Object.entries(state.pendingMoves).forEach(([pmId, move]) => {
   312→        const pm = state.pmSchedule.find((p) => p.id === pmId);
   313→        if (pm) {
   314→          pm.targetDate = move.originalDate;
   315→        }
   316→      });
   317→      state.pendingMoves = {};
   318→    },
   319→
   320→    // Cache Management
   321→    clearConstraintCache: (s) => {
   322→      const state = s as PmSliceState;
   323→      state.constraintCache = {};
   324→    },
   325→
   326→    invalidateConstraintCache: (s, pmId: string) => {
   327→      const state = s as PmSliceState;
   328→      Object.keys(state.constraintCache).forEach((key) => {
   329→        if (key.startsWith(`${pmId}:`)) {
   330→          delete state.constraintCache[key];
   331→        }
   332→      });
   333→    },
   334→
   335→    // Reset
   336→    reset: (s) => {
   337→      const state = s as PmSliceState;
   338→      Object.assign(state, initialPmState);
   339→    },
   340→  },
   341→});
   342→
   343→// =============================================================================
   344→// Async PM Slice
   345→// =============================================================================
   346→
   347→export interface PmApiResponse {
   348→  schedule: PmScheduleEntry[];
   349→  types: PmType[];
   350→}
   351→
   352→export const pmAsyncSlice = createAsyncSlice({
   353→  id: 'pmApi',
   354→  cache: {
   355→    policy: 'public',
   356→    ttl: '2m',
   357→    swr: true,
   358→  },
   359→  context: {
   360→    baseUrl: '/api/v1',
   361→    startDate: new Date().toISOString().split('T')[0],
   362→    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
   363→  },
   364→  load: async (ctx) => {
   365→    const { baseUrl, startDate, endDate } = ctx as {
   366→      baseUrl: string;
   367→      startDate: string;
   368→      endDate: string;
   369→    };
   370→
   371→    const [scheduleRes, typesRes] = await Promise.all([
   372→      fetch(`${baseUrl}/pm/schedule?startDate=${startDate}&endDate=${endDate}&pageSize=1000`),
   373→      fetch(`${baseUrl}/pm/types`),
   374→    ]);
   375→
   376→    if (!scheduleRes.ok || !typesRes.ok) {
   377→      throw new Error('Failed to fetch PM data');
   378→    }
   379→
   380→    const [scheduleData, typesData] = await Promise.all([
   381→      scheduleRes.json() as Promise<{ data: PmScheduleEntry[] }>,
   382→      typesRes.json() as Promise<{ data: PmType[] }>,
   383→    ]);
   384→
   385→    return {
   386→      schedule: scheduleData.data,
   387→      types: typesData.data,
   388→    };
   389→  },
   390→});
   391→
   392→// =============================================================================
   393→// Selectors
   394→// =============================================================================
   395→
   396→export function selectPmById(state: PmSliceState, pmId: string): PmScheduleEntry | undefined {
   397→  return state.pmSchedule.find((p) => p.id === pmId);
   398→}
   399→
   400→export function selectPmsByTrain(state: PmSliceState, trainId: string): PmScheduleEntry[] {
   401→  return state.pmSchedule.filter((p) => p.trainId === trainId);
   402→}
   403→
   404→export function selectPmsInRange(
   405→  state: PmSliceState,
   406→  startDate: string,
   407→  endDate: string
   408→): PmScheduleEntry[] {
   409→  return state.pmSchedule.filter((p) => p.targetDate >= startDate && p.targetDate <= endDate);
   410→}
   411→
   412→export function selectLockedPmCount(state: PmSliceState): number {
   413→  return Object.keys(state.lockedPmIds).length;
   414→}
   415→
   416→export function isPmBeingDragged(state: PmSliceState, pmId: string): boolean {
   417→  return state.drag.isDragging && state.drag.pmId === pmId;
   418→}
   419→
