/**
 * PM Slice
 *
 * State management for PM schedules, drag-drop interactions, and constraints.
 * Handles real-time validation during drag operations.
 *
 * @see specs/006-user-interface.md Section 6.4
 */

import { createSlice, createAsyncSlice } from '@belt/tools';
import type {
  PmScheduleEntry,
  PmType,
  DragState,
  ConstraintViolation,
  PmStatus,
} from '../types';

// =============================================================================
// PM Slice State
// =============================================================================

interface UndoEntry {
  pmId: string;
  previousDate: string;
  newDate: string;
  timestamp: number;
}

interface PendingMove {
  targetDate: string;
  originalDate: string;
}

export interface PmSliceState {
  pmSchedule: PmScheduleEntry[];
  pmTypes: PmType[];
  drag: DragState;
  lockedPmIds: Record<string, boolean>;
  editingPmId: string | null;
  pendingMoves: Record<string, PendingMove>;
  constraintCache: Record<string, ConstraintViolation[]>;
  lastValidation: number | null;
  undoStack: UndoEntry[];
  maxUndoDepth: number;
  [key: string]: unknown;
}

const initialPmState: PmSliceState = {
  pmSchedule: [],
  pmTypes: [],
  drag: {
    isDragging: false,
    pmId: null,
    sourceDate: null,
    targetDate: null,
    isValid: true,
    validationMessage: null,
    constraintViolations: [],
  },
  lockedPmIds: {},
  editingPmId: null,
  pendingMoves: {},
  constraintCache: {},
  lastValidation: null,
  undoStack: [],
  maxUndoDepth: 50,
};

export const pmSlice = createSlice({
  id: 'pm',
  initial: initialPmState,
  cache: { policy: 'session' },
  reducers: {
    // PM Schedule Operations
    setPmSchedule: (s, schedule: PmScheduleEntry[]) => {
      const state = s as PmSliceState;
      state.pmSchedule = schedule;
    },

    setPmTypes: (s, types: PmType[]) => {
      const state = s as PmSliceState;
      state.pmTypes = types;
    },

    updatePm: (s, pm: Partial<PmScheduleEntry> & { id: string }) => {
      const state = s as PmSliceState;
      const index = state.pmSchedule.findIndex((p) => p.id === pm.id);
      if (index !== -1) {
        state.pmSchedule[index] = { ...state.pmSchedule[index], ...pm };
      }
    },

    addPm: (s, pm: PmScheduleEntry) => {
      const state = s as PmSliceState;
      state.pmSchedule.push(pm);
    },

    removePm: (s, pmId: string) => {
      const state = s as PmSliceState;
      state.pmSchedule = state.pmSchedule.filter((p) => p.id !== pmId);
    },

    updatePmStatus: (s, payload: { pmId: string; status: PmStatus }) => {
      const state = s as PmSliceState;
      const pm = state.pmSchedule.find((p) => p.id === payload.pmId);
      if (pm) {
        pm.status = payload.status;
      }
    },

    // Drag and Drop
    startDrag: (s, payload: { pmId: string; sourceDate: string }) => {
      const state = s as PmSliceState;
      if (state.lockedPmIds[payload.pmId]) {
        return;
      }

      state.drag = {
        isDragging: true,
        pmId: payload.pmId,
        sourceDate: payload.sourceDate,
        targetDate: payload.sourceDate,
        isValid: true,
        validationMessage: null,
        constraintViolations: [],
      };
    },

    updateDragTarget: (s, targetDate: string) => {
      const state = s as PmSliceState;
      if (!state.drag.isDragging) return;

      state.drag.targetDate = targetDate;

      const cacheKey = `${state.drag.pmId}:${targetDate}`;
      const cachedViolations = state.constraintCache[cacheKey];

      if (cachedViolations) {
        state.drag.constraintViolations = cachedViolations;
        state.drag.isValid = cachedViolations.every((v) => v.severity !== 'ERROR');
        state.drag.validationMessage =
          cachedViolations.length > 0
            ? cachedViolations.map((v) => v.message).join('; ')
            : null;
      }
    },

    setDragValidation: (
      s,
      payload: {
        isValid: boolean;
        message: string | null;
        violations: ConstraintViolation[];
      }
    ) => {
      const state = s as PmSliceState;
      state.drag.isValid = payload.isValid;
      state.drag.validationMessage = payload.message;
      state.drag.constraintViolations = payload.violations;

      if (state.drag.pmId && state.drag.targetDate) {
        const cacheKey = `${state.drag.pmId}:${state.drag.targetDate}`;
        state.constraintCache[cacheKey] = payload.violations;
      }
      state.lastValidation = Date.now();
    },

    endDrag: (s, commit: boolean) => {
      const state = s as PmSliceState;
      if (!state.drag.isDragging || !state.drag.pmId) {
        state.drag = {
          isDragging: false,
          pmId: null,
          sourceDate: null,
          targetDate: null,
          isValid: true,
          validationMessage: null,
          constraintViolations: [],
        };
        return;
      }

      if (commit && state.drag.isValid && state.drag.targetDate !== state.drag.sourceDate) {
        const pm = state.pmSchedule.find((p) => p.id === state.drag.pmId);
        if (pm) {
          state.undoStack.push({
            pmId: state.drag.pmId,
            previousDate: state.drag.sourceDate!,
            newDate: state.drag.targetDate!,
            timestamp: Date.now(),
          });

          if (state.undoStack.length > state.maxUndoDepth) {
            state.undoStack.shift();
          }

          pm.targetDate = state.drag.targetDate!;

          state.pendingMoves[state.drag.pmId] = {
            targetDate: state.drag.targetDate!,
            originalDate: state.drag.sourceDate!,
          };
        }
      }

      state.drag = {
        isDragging: false,
        pmId: null,
        sourceDate: null,
        targetDate: null,
        isValid: true,
        validationMessage: null,
        constraintViolations: [],
      };
    },

    cancelDrag: (s) => {
      const state = s as PmSliceState;
      state.drag = {
        isDragging: false,
        pmId: null,
        sourceDate: null,
        targetDate: null,
        isValid: true,
        validationMessage: null,
        constraintViolations: [],
      };
    },

    // Undo/Redo
    undoLastMove: (s) => {
      const state = s as PmSliceState;
      const lastMove = state.undoStack.pop();
      if (lastMove) {
        const pm = state.pmSchedule.find((p) => p.id === lastMove.pmId);
        if (pm) {
          pm.targetDate = lastMove.previousDate;
          delete state.pendingMoves[lastMove.pmId];
        }
      }
    },

    clearUndoStack: (s) => {
      const state = s as PmSliceState;
      state.undoStack = [];
    },

    // Locking
    lockPm: (s, pmId: string) => {
      const state = s as PmSliceState;
      state.lockedPmIds[pmId] = true;
      const pm = state.pmSchedule.find((p) => p.id === pmId);
      if (pm) {
        pm.isLocked = true;
      }
    },

    unlockPm: (s, pmId: string) => {
      const state = s as PmSliceState;
      delete state.lockedPmIds[pmId];
      const pm = state.pmSchedule.find((p) => p.id === pmId);
      if (pm) {
        pm.isLocked = false;
        pm.lockedBy = null;
        pm.lockedAt = null;
      }
    },

    setLockedPms: (s, pmIds: string[]) => {
      const state = s as PmSliceState;
      state.lockedPmIds = {};
      pmIds.forEach((id) => {
        state.lockedPmIds[id] = true;
      });
    },

    // Editing
    startEditing: (s, pmId: string) => {
      const state = s as PmSliceState;
      if (!state.lockedPmIds[pmId]) {
        state.editingPmId = pmId;
      }
    },

    stopEditing: (s) => {
      const state = s as PmSliceState;
      state.editingPmId = null;
    },

    // Pending Moves
    confirmMove: (s, pmId: string) => {
      const state = s as PmSliceState;
      delete state.pendingMoves[pmId];
    },

    rejectMove: (s, pmId: string) => {
      const state = s as PmSliceState;
      const pending = state.pendingMoves[pmId];
      if (pending) {
        const pm = state.pmSchedule.find((p) => p.id === pmId);
        if (pm) {
          pm.targetDate = pending.originalDate;
        }
        delete state.pendingMoves[pmId];
      }
    },

    clearPendingMoves: (s) => {
      const state = s as PmSliceState;
      Object.entries(state.pendingMoves).forEach(([pmId, move]) => {
        const pm = state.pmSchedule.find((p) => p.id === pmId);
        if (pm) {
          pm.targetDate = move.originalDate;
        }
      });
      state.pendingMoves = {};
    },

    // Cache Management
    clearConstraintCache: (s) => {
      const state = s as PmSliceState;
      state.constraintCache = {};
    },

    invalidateConstraintCache: (s, pmId: string) => {
      const state = s as PmSliceState;
      Object.keys(state.constraintCache).forEach((key) => {
        if (key.startsWith(`${pmId}:`)) {
          delete state.constraintCache[key];
        }
      });
    },

    // Reset
    reset: (s) => {
      const state = s as PmSliceState;
      Object.assign(state, initialPmState);
    },
  },
});

// =============================================================================
// Async PM Slice
// =============================================================================

export interface PmApiResponse {
  schedule: PmScheduleEntry[];
  types: PmType[];
}

export const pmAsyncSlice = createAsyncSlice({
  id: 'pmApi',
  cache: {
    policy: 'public',
    ttl: '2m',
    swr: true,
  },
  context: {
    baseUrl: '/api/v1',
    startDate: new Date().toISOString().split('T')[0],
    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
  },
  load: async (ctx) => {
    const { baseUrl, startDate, endDate } = ctx as {
      baseUrl: string;
      startDate: string;
      endDate: string;
    };

    const [scheduleRes, typesRes] = await Promise.all([
      fetch(`${baseUrl}/pm/schedule?startDate=${startDate}&endDate=${endDate}&pageSize=1000`),
      fetch(`${baseUrl}/pm/types`),
    ]);

    if (!scheduleRes.ok || !typesRes.ok) {
      throw new Error('Failed to fetch PM data');
    }

    const [scheduleData, typesData] = await Promise.all([
      scheduleRes.json() as Promise<{ data: PmScheduleEntry[] }>,
      typesRes.json() as Promise<{ data: PmType[] }>,
    ]);

    return {
      schedule: scheduleData.data,
      types: typesData.data,
    };
  },
});

// =============================================================================
// Selectors
// =============================================================================

export function selectPmById(state: PmSliceState, pmId: string): PmScheduleEntry | undefined {
  return state.pmSchedule.find((p) => p.id === pmId);
}

export function selectPmsByTrain(state: PmSliceState, trainId: string): PmScheduleEntry[] {
  return state.pmSchedule.filter((p) => p.trainId === trainId);
}

export function selectPmsInRange(
  state: PmSliceState,
  startDate: string,
  endDate: string
): PmScheduleEntry[] {
  return state.pmSchedule.filter((p) => p.targetDate >= startDate && p.targetDate <= endDate);
}

export function selectLockedPmCount(state: PmSliceState): number {
  return Object.keys(state.lockedPmIds).length;
}

export function isPmBeingDragged(state: PmSliceState, pmId: string): boolean {
  return state.drag.isDragging && state.drag.pmId === pmId;
}

export function hasPendingMove(state: PmSliceState, pmId: string): boolean {
  return pmId in state.pendingMoves;
}

export function selectPmTypeById(state: PmSliceState, typeId: string): PmType | undefined {
  return state.pmTypes.find((t) => t.id === typeId);
}

export function selectPmStats(state: PmSliceState): {
  total: number;
  scheduled: number;
  inProgress: number;
  completed: number;
  deferred: number;
  cancelled: number;
  locked: number;
} {
  const schedule = state.pmSchedule;
  return {
    total: schedule.length,
    scheduled: schedule.filter((p) => p.status === 'SCHEDULED').length,
    inProgress: schedule.filter((p) => p.status === 'IN_PROGRESS').length,
    completed: schedule.filter((p) => p.status === 'COMPLETED').length,
    deferred: schedule.filter((p) => p.status === 'DEFERRED').length,
    cancelled: schedule.filter((p) => p.status === 'CANCELLED').length,
    locked: Object.keys(state.lockedPmIds).length,
  };
}

export function selectPmsWithViolations(
  state: PmSliceState
): Array<{ pm: PmScheduleEntry; violations: ConstraintViolation[] }> {
  const result: Array<{ pm: PmScheduleEntry; violations: ConstraintViolation[] }> = [];

  state.pmSchedule.forEach((pm) => {
    const cacheKey = `${pm.id}:${pm.targetDate}`;
    const violations = state.constraintCache[cacheKey];
    if (violations && violations.length > 0) {
      result.push({ pm, violations });
    }
  });

  return result;
}

/**
 * MMS Audit & History Tables
 *
 * Immutable audit trail for compliance with 12-year government contract.
 * All PM schedule changes and significant actions are logged.
 *
 * Key requirements:
 * - Full attribution (who, when, why)
 * - Before/after values for all changes
 * - Optimizer decisions must include explanation traces
 * - Compliance flags for safety-critical changes
 *
 * @see specs/003-database-schema.md Section 3.11
 */

import { relations } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  inet,
  jsonb,
  pgTable,
  text,
  timestamp,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { auditActionEnum, changeSourceEnum, pmChangeTypeEnum, pmStatusEnum } from './enums';
import { pmSchedule } from './pm-management';
import { users } from './users';

/**
 * PM Schedule History - Detailed change tracking for PM records
 *
 * Every change to a PM schedule is logged here.
 * Includes optimizer context when changes are suggested by the optimizer.
 *
 * Change types:
 * - CREATED: New PM scheduled
 * - DATE_CHANGED: Target date moved
 * - STATUS_CHANGED: Status transition
 * - TRACK_ASSIGNED: Track allocation changed
 * - LOCKED/UNLOCKED: Lock state changed
 * - COMPLETED/CANCELLED/DEFERRED: Terminal states
 */
export const pmScheduleHistory = pgTable(
  'pm_schedule_history',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    pmScheduleId: uuid('pm_schedule_id')
      .notNull()
      .references(() => pmSchedule.id),

    changeType: pmChangeTypeEnum('change_type').notNull(),

    // Previous values
    oldTargetDate: date('old_target_date'),
    oldStatus: pmStatusEnum('old_status'),
    oldAssignedTrackId: uuid('old_assigned_track_id'),
    oldAssignedHours: decimal('old_assigned_hours', { precision: 6, scale: 2 }),

    // New values
    newTargetDate: date('new_target_date'),
    newStatus: pmStatusEnum('new_status'),
    newAssignedTrackId: uuid('new_assigned_track_id'),
    newAssignedHours: decimal('new_assigned_hours', { precision: 6, scale: 2 }),

    // Attribution
    changedBy: uuid('changed_by')
      .notNull()
      .references(() => users.id),
    changedAt: timestamp('changed_at', { withTimezone: true }).defaultNow(),
    changeReason: text('change_reason'),
    changeSource: changeSourceEnum('change_source').default('USER'),

    // Optimizer context (if change was suggested by optimizer)
    optimizerRequestId: uuid('optimizer_request_id'),
    optimizerExplanation: jsonb('optimizer_explanation'),
  },
  (table) => [
    index('idx_pm_history_schedule').on(table.pmScheduleId, table.changedAt),
    index('idx_pm_history_date').on(table.changedAt),
    index('idx_pm_history_user').on(table.changedBy, table.changedAt),
  ]
);

/**
 * Audit Log - General system audit trail
 *
 * Captures all significant actions across the system.
 * Used for compliance reporting and investigation.
 *
 * Actions:
 * - CREATE, UPDATE, DELETE: Data modifications
 * - APPROVE, REJECT: Workflow decisions
 * - PUBLISH: Baseline publication
 */
export const auditLog = pgTable(
  'audit_log',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    // What
    entityType: varchar('entity_type', { length: 50 }).notNull(), // 'pm_schedule', 'baseline', etc.
    entityId: uuid('entity_id').notNull(),
    action: auditActionEnum('action').notNull(),

    // Who
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id),
    userEmail: varchar('user_email', { length: 255 }),
    userIpAddress: inet('user_ip_address'),

    // When
    occurredAt: timestamp('occurred_at', { withTimezone: true }).defaultNow(),

    // Details
    oldValues: jsonb('old_values'),
    newValues: jsonb('new_values'),
    metadata: jsonb('metadata'), // Additional context

    // Compliance
    complianceFlags: text('compliance_flags').array(), // ['SAFETY_CRITICAL', 'FINANCIAL']
  },
  (table) => [
    index('idx_audit_entity').on(table.entityType, table.entityId, table.occurredAt),
    index('idx_audit_user').on(table.userId, table.occurredAt),
    index('idx_audit_date').on(table.occurredAt),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const pmScheduleHistoryRelations = relations(pmScheduleHistory, ({ one }) => ({
  pmScheduleRecord: one(pmSchedule, {
    fields: [pmScheduleHistory.pmScheduleId],
    references: [pmSchedule.id],
  }),
  changedByUser: one(users, {
    fields: [pmScheduleHistory.changedBy],
    references: [users.id],
  }),
}));

export const auditLogRelations = relations(auditLog, ({ one }) => ({
  user: one(users, {
    fields: [auditLog.userId],
    references: [users.id],
  }),
}));

