   517→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for locking', requestId), 400);
   518→  }
   519→
   520→  const service = getService();
   521→  const user = c.get('user');
   522→
   523→  // Get PM with train details for broadcast
   524→  const pm = await service.getPm(pmId);
   525→
