   529→  const hub = getWebSocketHub();
   530→  hub.broadcastPmLocked({
   531→    pmId: updated.id,
   532→    trainId: pm.trainId,
   533→    trainNumber: pm.train?.trainNumber ?? 'Unknown',
   534→    isLocked: true,
   535→    lockedReason: body.reason,
   536→    lockedBy: {
   537→      userId: user?.id ?? 'system',
   538→      displayName: user?.email ?? 'System',
   539→    },
   540→  });
   541→
   542→  return c.json(
   543→    success({
   544→      id: updated.id,
   545→      isLocked: updated.isLocked,
   546→      lockedReason: updated.lockedReason,
   547→      lockedBy: updated.lockedBy,
   548→      lockedAt: updated.lockedAt,
   549→    })
   550→  );
   551→});
   552→
   553→/**
   554→ * POST /pm/schedule/:id/unlock
   555→ *
   556→ * Unlock a PM to allow optimizer changes.
   557→ */
   558→pmScheduleRoutes.post('/pm/schedule/:id/unlock', async (c) => {
   559→  const requestId = getRequestId(c);
   560→  const pmId = c.req.param('id');
   561→
   562→  if (!isValidUuid(pmId)) {
   563→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   564→  }
   565→
   566→  const service = getService();
