   577→    pmId: updated.id,
   578→    trainId: pm.trainId,
   579→    trainNumber: pm.train?.trainNumber ?? 'Unknown',
   580→    isLocked: false,
   581→    lockedBy: {
   582→      userId: user?.id ?? 'system',
   583→      displayName: user?.email ?? 'System',
   584→    },
   585→  });
   586→
   587→  return c.json(
   588→    success({
   589→      id: updated.id,
