/**
 * Detail Card Overlay
 *
 * React DOM overlay for the detail view (zoom levels 16+).
 * Provides rich PM editing interfaces with:
 * - Full PM details in expandable cards
 * - Inline editing (date, depot, track, shift)
 * - Crew assignment display
 * - Material status with availability badges
 * - Compliance window timeline visualization
 * - Change history panel
 * - Real-time constraint validation feedback
 *
 * Uses BlueprintJS components for consistent UI.
 * State managed via @belt/tools (no React hooks).
 *
 * @see specs/006-user-interface.md Section 6.3.4, 6.3.5
 */

import { useRef } from 'react';
import {
  Card,
  Elevation,
  Tag,
  Intent,
  Button,
  ButtonGroup,
  Collapse,
  Icon,
  ProgressBar,
  Divider,
  HTMLTable,
  Tooltip,
  Position,
  Popover,
  Menu,
  MenuItem,
  MenuDivider,
} from '@blueprintjs/core';

import type { OperationalPmBlock, OperationalCanvasData, MaterialStatus } from './types';
import { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS } from '../../theme/colors';

// =============================================================================
// Types
// =============================================================================

export interface DetailPmBlock extends OperationalPmBlock {
  /** Change history for audit trail */
  changeHistory?: ChangeHistoryEntry[];
  /** Constraint validation results */
  constraintValidation?: DetailConstraintValidation;
  /** Assigned crew (if available) */
  assignedCrew?: CrewAssignment[];
}

export interface ChangeHistoryEntry {
  id: string;
  timestamp: string;
  changeType: 'CREATE' | 'MOVE' | 'REASSIGN' | 'LOCK' | 'UNLOCK' | 'STATUS_CHANGE';
  field?: string;
  oldValue?: string;
  newValue?: string;
  userId: string;
  userName: string;
  reason?: string;
}

export interface DetailConstraintValidation {
  isValid: boolean;
  violations: DetailConstraintViolation[];
  warnings: DetailConstraintWarning[];
}

export interface DetailConstraintViolation {
  type: 'HARD' | 'SOFT';
  constraint: string;
  message: string;
  canOverride: boolean;
}

export interface DetailConstraintWarning {
  type: string;
  message: string;
}

export interface CrewAssignment {
  crewId: string;
  crewName: string;
  role: string;
  shift: string;
}

export interface DetailCanvasData extends OperationalCanvasData {
  pmBlocks: DetailPmBlock[];
}

export interface DetailCardOverlayProps {
  data: DetailCanvasData | null;
  fromDate: Date;
  toDate: Date;
  width: number;
  height: number;
  selectedPmIds?: string[];
  expandedPmIds?: string[];
  onPmSelect?: (pmId: string) => void;
  onPmExpand?: (pmId: string) => void;
  onPmCollapse?: (pmId: string) => void;
  onPmEdit?: (pmId: string, field: string, value: unknown) => void;
  onPmLock?: (pmId: string) => void;
  onPmUnlock?: (pmId: string) => void;
  onPmMove?: (pmId: string, newDate: string) => void;
  onViewHistory?: (pmId: string) => void;
  showGrid?: boolean;
}

// =============================================================================
// Constants
// =============================================================================

const LAYOUT = {
  HEADER_HEIGHT: 80,
  TRAIN_LABEL_WIDTH: 160,
  CARD_WIDTH: 360,
  CARD_EXPANDED_WIDTH: 480,
  CARD_HEIGHT: 200,
  CARD_EXPANDED_HEIGHT: 500,
  CARD_MARGIN: 16,
  DAY_WIDTH: 120,
  ROW_HEIGHT: 220,
  EXPANDED_ROW_HEIGHT: 520,
  GRID_LINE_COLOR: '#e2e8f0',
  FONT_FAMILY: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
};

const PM_STATUS_INTENT: Record<string, Intent> = {
  SCHEDULED: Intent.PRIMARY,
  IN_PROGRESS: Intent.WARNING,
  COMPLETED: Intent.SUCCESS,
  CANCELLED: Intent.NONE,
  DEFERRED: Intent.NONE,
  OVERDUE: Intent.DANGER,
};

// =============================================================================
// Utility Functions
// =============================================================================

function getPmStatusColor(status: string): string {
  const normalizedStatus = status.toLowerCase().replace('_', '') as keyof typeof PM_STATUS_COLORS;
  return PM_STATUS_COLORS[normalizedStatus] ?? PM_STATUS_COLORS.scheduled;
}

function getPmStatusIntent(status: string): Intent {
  return PM_STATUS_INTENT[status] ?? Intent.NONE;
}

function getMaterialStatusIcon(status: MaterialStatus): string {
  switch (status) {
    case 'AVAILABLE':
      return 'tick-circle';
    case 'LOW_STOCK':
      return 'warning-sign';
    case 'UNAVAILABLE':
      return 'error';
    case 'ARRIVING':
      return 'time';
    default:
      return 'help';
  }
}

function getMaterialStatusIntent(status: MaterialStatus): Intent {
  switch (status) {
    case 'AVAILABLE':
      return Intent.SUCCESS;
    case 'LOW_STOCK':
      return Intent.WARNING;
    case 'UNAVAILABLE':
      return Intent.DANGER;
    case 'ARRIVING':
      return Intent.PRIMARY;
    default:
      return Intent.NONE;
  }
}

function formatDate(dateStr: string): string {
  const date = new Date(dateStr);
  return date.toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
}

function formatDateTime(dateStr: string): string {
  const date = new Date(dateStr);
  return date.toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

function getDays(fromDate: Date, toDate: Date): Date[] {
  const days: Date[] = [];
  const current = new Date(fromDate);
  while (current <= toDate) {
    days.push(new Date(current));
    current.setDate(current.getDate() + 1);
  }
  return days;
}

function dateDiffDays(a: Date, b: Date): number {
  return Math.floor((a.getTime() - b.getTime()) / (1000 * 60 * 60 * 24));
}

function parseDate(dateStr: string): Date {
  return new Date(dateStr + 'T00:00:00');
}

function buildTrainGroups(pmBlocks: DetailPmBlock[]): Map<string, DetailPmBlock[]> {
  const groups = new Map<string, DetailPmBlock[]>();
  for (const pm of pmBlocks) {
    if (!groups.has(pm.trainId)) {
      groups.set(pm.trainId, []);
    }
    groups.get(pm.trainId)!.push(pm);
  }
  return groups;
}

function calculateComplianceProgress(pm: DetailPmBlock): {
  progress: number;
  daysRemaining: number;
  status: 'ok' | 'approaching' | 'violation';
} {
  const constraintStart = parseDate(pm.constraintStart);
  const constraintEnd = parseDate(pm.constraintEnd);
  const targetDate = parseDate(pm.targetDate);
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const totalWindow = dateDiffDays(constraintEnd, constraintStart) || 1;
  const positionInWindow = dateDiffDays(targetDate, constraintStart);
  const daysRemaining = dateDiffDays(constraintEnd, today);
  const progress = Math.min(100, Math.max(0, (positionInWindow / totalWindow) * 100));

  let status: 'ok' | 'approaching' | 'violation' = 'ok';
  if (progress > 90 || daysRemaining < 0) {
    status = 'violation';
  } else if (progress > 70 || daysRemaining < 7) {
    status = 'approaching';
  }

  return { progress, daysRemaining, status };
}

// =============================================================================
// Sub-Components
// =============================================================================

interface ComplianceTimelineProps {
  pm: DetailPmBlock;
}

function ComplianceTimeline({ pm }: ComplianceTimelineProps) {
  const { progress, daysRemaining, status } = calculateComplianceProgress(pm);

  let progressIntent: Intent = Intent.SUCCESS;
  let statusColor: string = CONSTRAINT_COLORS.ok;
  if (status === 'violation') {
    progressIntent = Intent.DANGER;
    statusColor = CONSTRAINT_COLORS.hardViolation;
  } else if (status === 'approaching') {
    progressIntent = Intent.WARNING;
    statusColor = CONSTRAINT_COLORS.approaching;
  }

  return (
    <div style={{ marginTop: 12 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
        <span style={{ fontSize: 11, color: '#64748b' }}>Compliance Window</span>
        <span style={{ fontSize: 11, color: statusColor, fontWeight: 500 }}>
          {daysRemaining > 0 ? `${daysRemaining} days remaining` : 'Past deadline'}
        </span>
      </div>
      <ProgressBar
        value={progress / 100}
        intent={progressIntent}
        animate={false}
        stripes={false}
      />
      <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 4 }}>
        <span style={{ fontSize: 10, color: '#94a3b8' }}>
          {formatDate(pm.constraintStart)}
        </span>
        <span style={{ fontSize: 10, color: '#1e293b', fontWeight: 500 }}>
          Scheduled: {formatDate(pm.targetDate)}
        </span>
        <span style={{ fontSize: 10, color: '#94a3b8' }}>
          {formatDate(pm.constraintEnd)}
        </span>
      </div>
    </div>
  );
}

interface MaterialsSectionProps {
  materials: DetailPmBlock['materials'];
}

function MaterialsSection({ materials }: MaterialsSectionProps) {
  if (materials.length === 0) {
    return (
      <div style={{ padding: '12px 0', color: '#94a3b8', fontStyle: 'italic', fontSize: 12 }}>
        No materials required for this PM
      </div>
    );
  }

  return (
    <HTMLTable compact style={{ width: '100%', fontSize: 12 }}>
      <thead>
        <tr>
          <th>Material</th>
          <th style={{ textAlign: 'center' }}>Required</th>
          <th style={{ textAlign: 'center' }}>Available</th>
          <th style={{ textAlign: 'center' }}>Status</th>
        </tr>
      </thead>
      <tbody>
        {materials.map((material) => (
          <tr key={material.materialId}>
            <td>
              <Tooltip content={material.materialId} position={Position.TOP}>
                <span>{material.materialName}</span>
              </Tooltip>
            </td>
            <td style={{ textAlign: 'center' }}>{material.quantityRequired}</td>
            <td style={{ textAlign: 'center' }}>{material.quantityAvailable}</td>
            <td style={{ textAlign: 'center' }}>
              <Tag
                minimal
                icon={getMaterialStatusIcon(material.status) as 'tick-circle' | 'warning-sign' | 'error' | 'time' | 'help'}
                intent={getMaterialStatusIntent(material.status)}
              >
                {material.status.replace('_', ' ')}
              </Tag>
            </td>
          </tr>
        ))}
      </tbody>
    </HTMLTable>
  );
}

interface ChangeHistorySectionProps {
  history?: ChangeHistoryEntry[];
}

function ChangeHistorySection({ history }: ChangeHistorySectionProps) {
  if (!history || history.length === 0) {
    return (
      <div style={{ padding: '12px 0', color: '#94a3b8', fontStyle: 'italic', fontSize: 12 }}>
        No change history available
      </div>
    );
  }

  const getChangeIcon = (type: ChangeHistoryEntry['changeType']) => {
    switch (type) {
      case 'CREATE':
        return 'add';
      case 'MOVE':
        return 'move';
      case 'REASSIGN':
        return 'swap-horizontal';
      case 'LOCK':
        return 'lock';
      case 'UNLOCK':
        return 'unlock';
      case 'STATUS_CHANGE':
        return 'refresh';
      default:
        return 'history';
    }
  };

  return (
    <div style={{ maxHeight: 200, overflowY: 'auto' }}>
      {history.slice(0, 10).map((entry) => (
        <div
          key={entry.id}
          style={{
            display: 'flex',
            alignItems: 'flex-start',
            padding: '8px 0',
            borderBottom: '1px solid #f1f5f9',
          }}
        >
          <Icon
            icon={getChangeIcon(entry.changeType) as 'add' | 'move' | 'swap-horizontal' | 'lock' | 'unlock' | 'refresh' | 'history'}
            size={14}
            style={{ marginRight: 8, marginTop: 2, color: '#64748b' }}
          />
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 12, color: '#1e293b' }}>
              <strong>{entry.changeType.replace('_', ' ')}</strong>
              {entry.field && ` - ${entry.field}`}
            </div>
            {entry.oldValue && entry.newValue && (
              <div style={{ fontSize: 11, color: '#64748b' }}>
                {entry.oldValue} → {entry.newValue}
              </div>
            )}
            <div style={{ fontSize: 10, color: '#94a3b8' }}>
              {formatDateTime(entry.timestamp)} by {entry.userName}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

interface ConstraintValidationSectionProps {
  validation?: DetailConstraintValidation;
}

function ConstraintValidationSection({ validation }: ConstraintValidationSectionProps) {
  if (!validation) {
    return (
      <div style={{ padding: '12px 0' }}>
        <Tag intent={Intent.SUCCESS} icon="tick">
          All constraints satisfied
        </Tag>
      </div>
    );
  }

  if (validation.isValid && validation.warnings.length === 0) {
    return (
      <div style={{ padding: '12px 0' }}>
        <Tag intent={Intent.SUCCESS} icon="tick">
          All constraints satisfied
        </Tag>
      </div>
    );
  }

  return (
    <div style={{ padding: '8px 0' }}>
      {validation.violations.map((v, i) => (
        <div
          key={i}
          style={{
            display: 'flex',
            alignItems: 'center',
            padding: '6px 8px',
            marginBottom: 4,
            backgroundColor: v.type === 'HARD' ? '#fef2f2' : '#fefce8',
            borderRadius: 4,
            border: `1px solid ${v.type === 'HARD' ? '#fecaca' : '#fef08a'}`,
          }}
        >
          <Icon
            icon={v.type === 'HARD' ? 'error' : 'warning-sign'}
            intent={v.type === 'HARD' ? Intent.DANGER : Intent.WARNING}
            size={14}
            style={{ marginRight: 8 }}
          />
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 12, fontWeight: 500, color: v.type === 'HARD' ? '#dc2626' : '#ca8a04' }}>
              {v.constraint}
            </div>
            <div style={{ fontSize: 11, color: '#64748b' }}>{v.message}</div>
          </div>
          {v.canOverride && (
            <Button small minimal intent={Intent.WARNING}>
              Override
            </Button>
          )}
        </div>
      ))}
      {validation.warnings.map((w, i) => (
        <div
          key={`warn-${i}`}
          style={{
            display: 'flex',
            alignItems: 'center',
            padding: '4px 8px',
            marginBottom: 4,
            backgroundColor: '#f0f9ff',
            borderRadius: 4,
          }}
        >
          <Icon icon="info-sign" intent={Intent.PRIMARY} size={12} style={{ marginRight: 8 }} />
          <span style={{ fontSize: 11, color: '#0369a1' }}>{w.message}</span>
        </div>
      ))}
    </div>
  );
}

interface DetailCardProps {
  pm: DetailPmBlock;
  isSelected: boolean;
  isExpanded: boolean;
  onSelect?: () => void;
  onExpand?: () => void;
  onCollapse?: () => void;
  onEdit?: (field: string, value: unknown) => void;
  onLock?: () => void;
  onUnlock?: () => void;
  onMove?: (newDate: string) => void;
  onViewHistory?: () => void;
}

function DetailCard({
  pm,
  isSelected,
  isExpanded,
  onSelect,
  onExpand,
  onCollapse,
  onEdit,
  onLock,
  onUnlock,
  onViewHistory,
}: DetailCardProps) {
  const statusColor = pm.displayColor || getPmStatusColor(pm.status);
  const fleetColor = FLEET_COLORS[pm.fleetCode as keyof typeof FLEET_COLORS] || FLEET_COLORS.KS;
  const historyRef = useRef<HTMLDivElement>(null);
  const materialsRef = useRef<HTMLDivElement>(null);
  const constraintsRef = useRef<HTMLDivElement>(null);

  const cardWidth = isExpanded ? LAYOUT.CARD_EXPANDED_WIDTH : LAYOUT.CARD_WIDTH;

  const actionMenu = (
    <Menu>
      <MenuItem icon="edit" text="Edit Details" onClick={() => onEdit?.('all', null)} disabled={pm.isLocked} />
      <MenuItem icon="calendar" text="Reschedule" onClick={() => onEdit?.('targetDate', null)} disabled={pm.isLocked} />
      <MenuItem icon="swap-horizontal" text="Reassign Track" onClick={() => onEdit?.('track', null)} disabled={pm.isLocked} />
      <MenuDivider />
      {pm.isLocked ? (
        <MenuItem icon="unlock" text="Unlock PM" intent={Intent.WARNING} onClick={onUnlock} />
      ) : (
        <MenuItem icon="lock" text="Lock PM" onClick={onLock} />
      )}
      <MenuDivider />
      <MenuItem icon="history" text="View Full History" onClick={onViewHistory} />
    </Menu>
  );

  return (
    <Card
      elevation={isSelected ? Elevation.THREE : Elevation.ONE}
      interactive={!isExpanded}
      onClick={!isExpanded ? onSelect : undefined}
      style={{
        width: cardWidth,
        minHeight: isExpanded ? LAYOUT.CARD_EXPANDED_HEIGHT : LAYOUT.CARD_HEIGHT,
        borderLeft: `4px solid ${statusColor}`,
        outline: isSelected ? `2px solid #3b82f6` : 'none',
        outlineOffset: 2,
        transition: 'all 0.2s ease',
        position: 'relative',
        overflow: 'hidden',
      }}
    >
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'flex-start', marginBottom: 12 }}>
        <div style={{ flex: 1 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ fontSize: 16, fontWeight: 600, color: '#1e293b' }}>
              {pm.pmCode}
            </span>
            <Tag minimal intent={getPmStatusIntent(pm.status)}>
              {pm.status.replace('_', ' ')}
            </Tag>
            {pm.isLocked && (
              <Tooltip content="Locked in Maximo - Cannot be modified" position={Position.TOP}>
                <Icon icon="lock" size={14} style={{ color: '#d97706' }} />
              </Tooltip>
            )}
          </div>
          <div style={{ fontSize: 12, color: '#64748b', marginTop: 4 }}>
            {pm.pmDescription}
          </div>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
          {isExpanded ? (
            <Button small minimal icon="collapse-all" onClick={onCollapse} />
          ) : (
            <Button small minimal icon="expand-all" onClick={onExpand} />
          )}
          <Popover content={actionMenu} position={Position.BOTTOM_RIGHT}>
            <Button small minimal icon="more" />
          </Popover>
        </div>
      </div>

      {/* Train info row */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 12 }}>
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 6,
            padding: '4px 8px',
            backgroundColor: `${fleetColor}15`,
            borderRadius: 4,
          }}
        >
          <div
            style={{
              width: 4,
              height: 16,
              backgroundColor: fleetColor,
              borderRadius: 2,
            }}
          />
          <span style={{ fontSize: 13, fontWeight: 500, color: '#1e293b' }}>
            {pm.trainNumber}
          </span>
          <span style={{ fontSize: 11, color: '#64748b' }}>{pm.fleetCode}</span>
        </div>
        {pm.depotCode && (
          <div style={{ fontSize: 12, color: '#64748b' }}>
            <Icon icon="office" size={12} style={{ marginRight: 4 }} />
            {pm.depotCode}
          </div>
        )}
        {pm.trackNumber && (
          <div style={{ fontSize: 12, color: '#64748b' }}>
            <Icon icon="layout-grid" size={12} style={{ marginRight: 4 }} />
            Track {pm.trackNumber}
          </div>
        )}
      </div>

      {/* Date and duration row */}
      <div style={{ display: 'flex', gap: 16, marginBottom: 12 }}>
        <div>
          <div style={{ fontSize: 10, color: '#94a3b8', textTransform: 'uppercase' }}>Date</div>
          <div style={{ fontSize: 13, fontWeight: 500, color: '#1e293b' }}>
            {formatDate(pm.targetDate)}
            {pm.durationDays > 1 && (
              <span style={{ color: '#64748b', fontWeight: 400 }}>
                {' '}
                - {formatDate(pm.endDate)}
              </span>
            )}
          </div>
        </div>
        <div>
          <div style={{ fontSize: 10, color: '#94a3b8', textTransform: 'uppercase' }}>Duration</div>
          <div style={{ fontSize: 13, fontWeight: 500, color: '#1e293b' }}>
            {pm.durationDays} day{pm.durationDays > 1 ? 's' : ''}
            {pm.estimatedHours && (
              <span style={{ color: '#64748b', fontWeight: 400 }}> ({pm.estimatedHours}h)</span>
            )}
          </div>
        </div>
        {pm.assignedShift && (
          <div>
            <div style={{ fontSize: 10, color: '#94a3b8', textTransform: 'uppercase' }}>Shift</div>
            <div style={{ fontSize: 13, fontWeight: 500, color: '#1e293b' }}>{pm.assignedShift}</div>
          </div>
        )}
      </div>

      {/* Compliance timeline */}
      <ComplianceTimeline pm={pm} />

      {/* Expanded content */}
      <Collapse isOpen={isExpanded}>
        <Divider style={{ margin: '16px 0' }} />

        {/* Materials section */}
        <div ref={materialsRef}>
          <div style={{ fontSize: 12, fontWeight: 600, color: '#475569', marginBottom: 8 }}>
            <Icon icon="box" size={12} style={{ marginRight: 6 }} />
            Materials
          </div>
          <MaterialsSection materials={pm.materials} />
        </div>

        <Divider style={{ margin: '16px 0' }} />

        {/* Constraint validation */}
        <div ref={constraintsRef}>
          <div style={{ fontSize: 12, fontWeight: 600, color: '#475569', marginBottom: 8 }}>
            <Icon icon="shield" size={12} style={{ marginRight: 6 }} />
            Constraint Validation
          </div>
          <ConstraintValidationSection validation={pm.constraintValidation} />
        </div>

        <Divider style={{ margin: '16px 0' }} />

        {/* Change history */}
        <div ref={historyRef}>
          <div style={{ fontSize: 12, fontWeight: 600, color: '#475569', marginBottom: 8 }}>
            <Icon icon="history" size={12} style={{ marginRight: 6 }} />
            Recent Changes
          </div>
          <ChangeHistorySection history={pm.changeHistory} />
        </div>

        {/* Actions footer */}
        <Divider style={{ margin: '16px 0' }} />
        <ButtonGroup fill>
          <Button
            icon="edit"
            text="Edit"
            disabled={pm.isLocked}
            onClick={() => onEdit?.('all', null)}
          />
          <Button
            icon="calendar"
            text="Reschedule"
            disabled={pm.isLocked}
            onClick={() => onEdit?.('targetDate', null)}
          />
          {pm.isLocked ? (
            <Button icon="unlock" text="Unlock" intent={Intent.WARNING} onClick={onUnlock} />
          ) : (
            <Button icon="lock" text="Lock" onClick={onLock} />
          )}
          <Button icon="history" text="History" onClick={onViewHistory} />
        </ButtonGroup>
      </Collapse>
    </Card>
  );
}

// =============================================================================
// Main Component
// =============================================================================

export function DetailCardOverlay({
  data,
  fromDate,
  toDate,
  width,
  height,
  selectedPmIds = [],
  expandedPmIds = [],
  onPmSelect,
  onPmExpand,
  onPmCollapse,
  onPmEdit,
  onPmLock,
  onPmUnlock,
  onViewHistory,
}: DetailCardOverlayProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  if (!data) {
    return null;
  }

  const days = getDays(fromDate, toDate);
  const trainGroups = buildTrainGroups(data.pmBlocks);
  const trainOrder = Array.from(trainGroups.keys());
  const selectedSet = new Set(selectedPmIds);
  const expandedSet = new Set(expandedPmIds);

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  return (
    <div
      ref={containerRef}
      style={{
        width,
        height,
        overflow: 'auto',
        backgroundColor: '#f8fafc',
        fontFamily: LAYOUT.FONT_FAMILY,
      }}
    >
      {/* Timeline header */}
      <div
        style={{
          position: 'sticky',
          top: 0,
          zIndex: 10,
          display: 'flex',
          backgroundColor: '#ffffff',
          borderBottom: '1px solid #e2e8f0',
        }}
      >
        {/* Train label header */}
        <div
          style={{
            width: LAYOUT.TRAIN_LABEL_WIDTH,
            minWidth: LAYOUT.TRAIN_LABEL_WIDTH,
            height: LAYOUT.HEADER_HEIGHT,
            padding: 16,
            backgroundColor: '#f8fafc',
            borderRight: '1px solid #e2e8f0',
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
          }}
        >
          <div style={{ fontSize: 14, fontWeight: 600, color: '#1e293b' }}>Trains</div>
          <div style={{ fontSize: 11, color: '#64748b' }}>{trainOrder.length} trains</div>
        </div>

        {/* Day columns */}
        <div style={{ display: 'flex' }}>
          {days.map((day) => {
            const isToday = day.getTime() === today.getTime();
            const isWeekend = day.getDay() === 0 || day.getDay() === 6;
            const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

            return (
              <div
                key={day.toISOString()}
                style={{
                  width: LAYOUT.DAY_WIDTH,
                  minWidth: LAYOUT.DAY_WIDTH,
                  height: LAYOUT.HEADER_HEIGHT,
                  padding: '12px 8px',
                  backgroundColor: isToday ? '#dbeafe' : isWeekend ? '#f1f5f9' : '#ffffff',
                  borderRight: '1px solid #e2e8f0',
                  textAlign: 'center',
                }}
              >
                <div
                  style={{
                    fontSize: 10,
                    color: isToday ? '#2563eb' : '#94a3b8',
                    textTransform: 'uppercase',
                    letterSpacing: '0.5px',
                  }}
                >
                  {dayNames[day.getDay()]}
                </div>
                <div
                  style={{
                    fontSize: 20,
                    fontWeight: isToday ? 700 : 500,
                    color: isToday ? '#2563eb' : '#1e293b',
                    marginTop: 4,
                  }}
                >
                  {day.getDate()}
                </div>
                <div style={{ fontSize: 11, color: '#64748b' }}>
                  {day.toLocaleDateString('en-US', { month: 'short' })}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Train rows */}
      {trainOrder.map((trainId) => {
        const pms = trainGroups.get(trainId) || [];
        const firstPm = pms[0];
        if (!firstPm) return null;

        const fleetColor = FLEET_COLORS[firstPm.fleetCode as keyof typeof FLEET_COLORS] || FLEET_COLORS.KS;
        const hasExpandedCard = pms.some((pm) => expandedSet.has(pm.pmId));
        const rowHeight = hasExpandedCard ? LAYOUT.EXPANDED_ROW_HEIGHT : LAYOUT.ROW_HEIGHT;

        return (
          <div
            key={trainId}
            style={{
              display: 'flex',
              borderBottom: '1px solid #e2e8f0',
              minHeight: rowHeight,
            }}
          >
            {/* Train label */}
            <div
              style={{
                width: LAYOUT.TRAIN_LABEL_WIDTH,
                minWidth: LAYOUT.TRAIN_LABEL_WIDTH,
                padding: 16,
                backgroundColor: '#ffffff',
                borderRight: '1px solid #e2e8f0',
                position: 'sticky',
                left: 0,
                zIndex: 5,
              }}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <div
                  style={{
                    width: 4,
                    height: 32,
                    backgroundColor: fleetColor,
                    borderRadius: 2,
                  }}
                />
                <div>
                  <div style={{ fontSize: 14, fontWeight: 600, color: '#1e293b' }}>
                    {firstPm.trainNumber}
                  </div>
                  <div style={{ fontSize: 11, color: '#64748b' }}>{firstPm.fleetCode}</div>
                </div>
              </div>
              <div style={{ marginTop: 12, fontSize: 11, color: '#94a3b8' }}>
                {pms.length} PM{pms.length !== 1 ? 's' : ''} scheduled
              </div>
            </div>

            {/* PM cards grid */}
            <div style={{ flex: 1, position: 'relative', padding: LAYOUT.CARD_MARGIN }}>
              {pms.map((pm) => {
                const pmDate = parseDate(pm.targetDate);
                const dayOffset = dateDiffDays(pmDate, fromDate);
                if (dayOffset < 0) return null;

                const isSelected = selectedSet.has(pm.pmId);
                const isExpanded = expandedSet.has(pm.pmId);

                const cardX = dayOffset * LAYOUT.DAY_WIDTH;

                return (
                  <div
                    key={pm.pmId}
                    style={{
                      position: 'absolute',
                      left: cardX,
                      top: 0,
                      zIndex: isExpanded ? 20 : isSelected ? 15 : 10,
                    }}
                  >
                    <DetailCard
                      pm={pm}
                      isSelected={isSelected}
                      isExpanded={isExpanded}
                      onSelect={() => onPmSelect?.(pm.pmId)}
                      onExpand={() => onPmExpand?.(pm.pmId)}
                      onCollapse={() => onPmCollapse?.(pm.pmId)}
                      onEdit={(field, value) => onPmEdit?.(pm.pmId, field, value)}
                      onLock={() => onPmLock?.(pm.pmId)}
                      onUnlock={() => onPmUnlock?.(pm.pmId)}
                      onViewHistory={() => onViewHistory?.(pm.pmId)}
                    />
                  </div>
                );
              })}

              {/* Today indicator line */}
              {(() => {
                const todayOffset = dateDiffDays(today, fromDate);
                if (todayOffset >= 0 && todayOffset < days.length) {
                  return (
                    <div
                      style={{
                        position: 'absolute',
                        left: todayOffset * LAYOUT.DAY_WIDTH + LAYOUT.DAY_WIDTH / 2,
                        top: 0,
                        bottom: 0,
                        width: 2,
                        backgroundColor: '#2563eb',
                        opacity: 0.3,
                        zIndex: 1,
                      }}
                    />
                  );
                }
                return null;
              })()}
            </div>
          </div>
        );
      })}
    </div>
  );
}

export default DetailCardOverlay;

